function slugify(value: string) {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
}

function toVerbItem(type: VerbType, seed: VerbSeed): VerbItem {
  const [verb1, verb2, verb3, meaning, pattern, difficulty, tier, context] = seed;
  const fullForms = `${verb1} - ${verb2} - ${verb3}`;

  return {
    id: `${type === "regular" ? "reg" : "irr"}-${slugify(verb1)}`,
    type,
    verb1,
    verb2,
    verb3,
    meaning,
    pattern,
    difficulty,
    tier,
    note: `Umum dalam konteks ${context}.`,
    commonMistake:
      type === "regular"
        ? `Jangan memakai bentuk tidak baku; gunakan "${fullForms}".`
        : `Jangan otomatis menambahkan -ed; hafalkan bentuk "${fullForms}".`,
  };
}

export const additionalRegularVerbs: VerbItem[] = regularSeeds.map((seed) =>
  toVerbItem("regular", seed),
);

export const additionalIrregularVerbs: VerbItem[] = irregularSeeds.map((seed) =>
  toVerbItem("irregular", seed),
);

if (additionalRegularVerbs.length !== 280) {
  throw new Error(`Expected 280 additional regular verbs, received ${additionalRegularVerbs.length}.`);
}

if (additionalIrregularVerbs.length !== 280) {
  throw new Error(
    `Expected 280 additional irregular verbs, received ${additionalIrregularVerbs.length}.`,
  );
}
